import{_ as t,o as r,c as n,a1 as e,j as o}from"./chunks/framework.BX4nIuL2.js";const m=JSON.parse('{"title":"Fab Lab","description":"","frontmatter":{},"headers":[],"relativePath":"courses/fab-course/doc/Fab/FAB.md","filePath":"courses/fab-course/doc/Fab/FAB.md"}'),i={name:"courses/fab-course/doc/Fab/FAB.md"};function l(s,a,h,b,c,d){return r(),n("div",null,[...a[0]||(a[0]=[e('<h1 id="fab-lab" tabindex="-1">Fab Lab <a class="header-anchor" href="#fab-lab" aria-label="Permalink to &quot;Fab Lab&quot;">​</a></h1><p>The Fab Lab Network is an open, creative community of fabricators, artists, scientists, engineers, educators, students, amateurs, professionals, of all ages located in more than 120 countries in approximately 2,000 Fab Labs. From community based labs to advanced research centers, Fab Labs share the goal of democratizing access to the tools for technical invention. This community is simultaneously a manufacturing network, a distributed technical education campus, and a distributed research laboratory working to digitize fabrication, inventing the next generation of manufacturing and personal fabrication <img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/WX20221028-092100@2x.png" alt=""><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/WX20221028-092834@2x.png" alt=""></p><h2 id="_1-aim" tabindex="-1">1 Aim <a class="header-anchor" href="#_1-aim" aria-label="Permalink to &quot;1 Aim&quot;">​</a></h2><h4 id="_1-1-the-fab-charter" tabindex="-1">1.1 The Fab Charter <a class="header-anchor" href="#_1-1-the-fab-charter" aria-label="Permalink to &quot;1.1 The Fab Charter&quot;">​</a></h4><ul><li><p><em><strong>What is a fab lab?</strong></em> Fab labs are a global network of local labs, enabling invention by providing access to tools for digital fabrication</p></li><li><p><em><strong>What’s in a fab lab?</strong></em> Fab labs share an evolving inventory of core capabilities to make (almost) anything, allowing people and projects to be shared</p></li><li><p><em><strong>What does the fab lab network provide?</strong></em> Operational, educational, technical, financial, and logistical assistance beyond what’s available within one lab</p></li><li><p><em><strong>Who can use a fab lab?</strong></em> Fab labs are available as a community resource, offering open access for individuals as well as scheduled access for programs</p></li><li><p><em><strong>What are your responsibilities?</strong></em></p><ul><li><em><strong>safety:</strong></em> not hurting people or machines</li><li><em><strong>operations:</strong></em> assisting with cleaning, maintaining, and improving the lab</li><li><em><strong>knowledge:</strong></em> contributing to documentation and instruction</li></ul></li><li><p><em><strong>Who owns fab lab inventions?</strong></em> Designs and processes developed in fab labs can be protected and sold however an inventor chooses, but should remain available for individuals to use and learn from</p></li><li><p><em><strong>How can businesses use a fab lab?</strong></em> Commercial activities can be prototyped and incubated in a fab lab, but they must not conflict with other uses, they should grow beyond rather than within the lab, and they are expected to benefit the inventors, labs, and networks that contribute to their success <img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/WX20221028-100621@2x.png" alt=""></p></li></ul><h4 id="_1-2-fab-foundation-and-mission" tabindex="-1">1.2 Fab Foundation and mission <a class="header-anchor" href="#_1-2-fab-foundation-and-mission" aria-label="Permalink to &quot;1.2 Fab Foundation and mission&quot;">​</a></h4><ul><li><a href="http://www.fabfoundation.org" target="_blank" rel="noreferrer">Fab foundation </a> is formed in 2009 to facilitate and support the growth of the international fab lab network as well as the development of regional capacity-building organizations. The Fab Foundation is a US non-profit 501(c) 3 organization that emerged from MIT’s Center for Bits &amp; Atoms Fab Lab Program.</li><li>Mission:Fablab&#39;s mission is to provide access to the tools, the knowledge and the financial means to educate, innovate and invent using technology and digital fabrication to allow anyone to make (almost) anything, and thereby creating opportunities to improve lives and livelihoods around the world. Community organizations, educational institutions and non-profit concerns are our primary beneficiaries.</li></ul><p><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/WX20221028-093649@2x.png" alt=""></p><h4 id="_1-3-businesses-emerging-from-fab-labs-and-the-digital-fabrication-network" tabindex="-1">1.3 Businesses emerging from fab labs and the digital fabrication network <a class="header-anchor" href="#_1-3-businesses-emerging-from-fab-labs-and-the-digital-fabrication-network" aria-label="Permalink to &quot;1.3 Businesses emerging from fab labs and the digital fabrication network&quot;">​</a></h4><ul><li><a href="https://formlabs.com/" target="_blank" rel="noreferrer">FormLab (Desktop SLA 3D printer)</a>;</li><li><a href="https://www.makerbot.com" target="_blank" rel="noreferrer">MakerBot (Desktop FDM 3D printer)</a></li><li><a href="http://www.modk.it/" target="_blank" rel="noreferrer">www.modk.it</a>;</li><li><a href="https://www.ponoko.com/" target="_blank" rel="noreferrer">Ponoko ( Designer and Robot fast produce customer&#39;s need )</a>;</li><li><a href="https://ultimaker.com" target="_blank" rel="noreferrer">Ultimaker (Desktop FDM 3D printer and open source slice software)</a>;</li><li><a href="https://www.geek.com/chips/fabfi-an-open-source-wireless-network-for-60-per-node-1395747/" target="_blank" rel="noreferrer">FabFi:an open source wireless network for $60 per node</a>;</li><li>Remake Electric;</li><li><a href="https://www.snap.com/" target="_blank" rel="noreferrer">Snap</a>;</li><li><a href="http://www.kickstarter.com/projects/1342319572/the-nifty-minidrive" target="_blank" rel="noreferrer">Nifty MiniDrive:An easy to use device that allows anyone to quickly and simply increase the available memory in their MacBook computer.</a></li></ul><h2 id="_2-fab-academy" tabindex="-1">2 Fab Academy <a class="header-anchor" href="#_2-fab-academy" aria-label="Permalink to &quot;2 Fab Academy&quot;">​</a></h2><p><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/WX20221028-093801@2x.png" alt=""></p><h2 id="_3-core-content" tabindex="-1">3 Core content <a class="header-anchor" href="#_3-core-content" aria-label="Permalink to &quot;3 Core content&quot;">​</a></h2><p>FAB academy is the key of fablab. this year&#39;s schedule in the <a href="http://fab.academany.org/2018/schedule.html" target="_blank" rel="noreferrer">following link</a>. <em><strong>In every week&#39;s cycle:</strong></em></p><ul><li>Wednesday:Neil introduce the general of content</li><li>Weekend:Local lab paractice</li><li>Monday:recitation(introduce some culture and practice about FAB)</li><li>Tuesday: area review:China(include Taiwan),Japan,South Korea)</li><li>Wednesday:Global review(communicate with 4-5 students about week&#39;s work and finial project)</li></ul><h2 id="_4-community-attender-and-organizer-global-net-and-china-net-fab-city-fab14" tabindex="-1">4 Community :Attender and Organizer ,Global net and China net, fab city,fab14+ <a class="header-anchor" href="#_4-community-attender-and-organizer-global-net-and-china-net-fab-city-fab14" aria-label="Permalink to &quot;4 Community :Attender and Organizer ,Global  net and China net, fab city,fab14+&quot;">​</a></h2><h4 id="_4-1-net" tabindex="-1">4.1 Net <a class="header-anchor" href="#_4-1-net" aria-label="Permalink to &quot;4.1 Net&quot;">​</a></h4><p><a href="https://www.fablabs.io/labs/map" target="_blank" rel="noreferrer">There are 1271 labs in the world</a>,24 labs in China has register fablab, <a href="https://www.fablabs.io/labs?country=cn" target="_blank" rel="noreferrer">more detail in the link</a></p><h4 id="_4-2-2018" tabindex="-1">4.2 2018 <a class="header-anchor" href="#_4-2-2018" aria-label="Permalink to &quot;4.2 2018&quot;">​</a></h4><p>There are 252 students attend the fab Academy in 64 labs. In China there are 9 students in 3labs(Shanghai,Shenzhen,Beijing)</p><h4 id="_4-3-china-attender" tabindex="-1">4.3 China attender <a class="header-anchor" href="#_4-3-china-attender" aria-label="Permalink to &quot;4.3 China attender&quot;">​</a></h4><p>In the history of China, there are about 25 attenders. The background is about maker space manager, STEAM teacher, startup company manager.</p><h4 id="_4-4-fab-14" tabindex="-1">4.4 Fab 14+ <a class="header-anchor" href="#_4-4-fab-14" aria-label="Permalink to &quot;4.4 Fab 14+&quot;">​</a></h4><p>Fablab annual meet <img src="https://ws2.sinaimg.cn/large/006tNc79ly1fr4iu5woryj31kw0puwkn.jpg" alt=""><img src="https://ws2.sinaimg.cn/large/006tNc79ly1fr4iu78no2j31kw0x7tej.jpg" alt=""></p><h4 id="_4-5-fab-city" tabindex="-1">4.5 Fab city <a class="header-anchor" href="#_4-5-fab-city" aria-label="Permalink to &quot;4.5 Fab city&quot;">​</a></h4><p>The Fab City project was launched in 2011 at the FAB7 conference in Lima by the <em><strong>Institutd’Arquitectura Avançada de Catalunya, the MIT Center for Bits and Atoms, the Fab Foundation and the Barcelona City Council</strong></em></p><p>FAB City is a new urban model of transforming and shaping cities that shifts how they source and use materials from ‘Products In Trash Out’ (PITO) to ‘Data In Data Out’ (DIDO). This means that more production occurs inside the city, along with recycling materials and meeting local needs through local inventiveness. A city’s imports and exports would mostly be found in the form of data (information, knowledge, design, code).</p><p>There are 18 cities attend the project:</p><ul><li>USA(Boston,Cambridge,Somerville,Sacramento,Detroit);</li><li>France(Toulouse,Occitane Region,Paris )</li><li>China:Shenzhen</li><li>South Africa:Ekurhuleni</li><li>India:The state of Kerala</li><li>The country of Georgia</li><li>Netherlands:Amsterdam</li><li>The state of Bhutan</li><li>Chile:Santiago</li></ul><h2 id="_5-develop" tabindex="-1">5 Develop <a class="header-anchor" href="#_5-develop" aria-label="Permalink to &quot;5 Develop&quot;">​</a></h2><p>Now Fablab do the work about basic knowledge, Innovation, design, prototype. They are also practice in Fab city, <a href="https://make.works/" target="_blank" rel="noreferrer">manufacture</a>, <a href="http://market.fablabs.io/" target="_blank" rel="noreferrer">market</a></p><h2 id="_6-how-to-set-up-a-fablab" tabindex="-1">6 how to set up a Fablab <a class="header-anchor" href="#_6-how-to-set-up-a-fablab" aria-label="Permalink to &quot;6 how to set up a Fablab&quot;">​</a></h2><ol><li><a href="http://www.fabfoundation.org/index.php/setting-up-a-fab-lab/index.html" target="_blank" rel="noreferrer">Guide and register </a></li><li>[hardware] (<a href="https://www.fablabs.io/machines" target="_blank" rel="noreferrer">https://www.fablabs.io/machines</a>):All Fab Labs share common tools and processes in order to build a global network, a distributed laboratory for research and invention. Here you can find and add all the Machines available in the global Fab Lab Network, a global database of technologies locally available</li><li><a href="https://a360.co/2wmHVpj" target="_blank" rel="noreferrer">Layout</a></li></ol>',33),o("iframe",{src:"https://myhub.autodesk360.com/ue28cacf9/shares/public/SHabee1QT1a327cf2b7a64135bb75dc3708d?mode=embed",width:"1024",height:"768",allowfullscreen:"true",webkitallowfullscreen:"true",mozallowfullscreen:"true",frameborder:"0"},null,-1),e('<h2 id="_7-reference" tabindex="-1">7 Reference <a class="header-anchor" href="#_7-reference" aria-label="Permalink to &quot;7 Reference&quot;">​</a></h2><ul><li><p><strong>Locations</strong> <a href="https://www.fablabs.io/labs/map" target="_blank" rel="noreferrer"> https://www.fablabs.io/labs/map </a></p></li><li><p><strong>Foundation</strong><a href="http://www.fabfoundation.org" target="_blank" rel="noreferrer"> http://www.fabfoundation.org </a></p></li><li><p><strong>Academy</strong> <a href="http://fabacademy.org" target="_blank" rel="noreferrer"> http://fabacademy.org </a>,<a href="http://fabacademy.org/2018/" target="_blank" rel="noreferrer">Fab academy 2018</a></p></li><li><p><strong>Events</strong> <a href="http://fabevent.org" target="_blank" rel="noreferrer"> http://fabevent.org </a></p></li><li><p><strong>Fab cities</strong> <a href="http://fab.city" target="_blank" rel="noreferrer"> http://fab.city </a></p></li><li><p><strong>Video</strong> <a href="http://ng.cba.mit.edu/show/video/16.08.fablabs.mp4" target="_blank" rel="noreferrer"> http://ng.cba.mit.edu/show/video/16.08.fablabs.mp4 </a></p></li><li><p><strong>Talk</strong> <a href="https://www.ted.com/talks/neil_gershenfeld_on_fab_labs" target="_blank" rel="noreferrer"> https://www.ted.com/talks/neil_gershenfeld_on_fab_labs </a></p></li><li><p><strong>Presentation</strong> <a href="http://ng.cba.mit.edu/show/script/17.09.fab.show.html" target="_blank" rel="noreferrer"> http://ng.cba.mit.edu/show/script/17.09.fab.show.html </a></p></li><li><p><strong>Article</strong> <a href="https://www.foreignaffairs.com/articles/2012-09-27/how-make-almost-anything" target="_blank" rel="noreferrer"> https://www.foreignaffairs.com/articles/2012-09-27/how-make-almost-anything </a></p></li><li><p><strong>Book</strong> <a href="http://designingreality.org/" target="_blank" rel="noreferrer"> http://designingreality.org/ </a></p></li><li><p><strong>Inventory</strong> <a href="http://fab.cba.mit.edu/about/fab/inv.html" target="_blank" rel="noreferrer"> http://fab.cba.mit.edu/about/fab/inv.html </a></p></li><li><p><strong>Charter</strong> <a href="http://fab.cba.mit.edu/about/charter" target="_blank" rel="noreferrer"> http://fab.cba.mit.edu/about/charter </a></p></li><li><p><strong>Cloud</strong> <a href="https://gitlab.fabcloud.org" target="_blank" rel="noreferrer"> https://gitlab.fabcloud.org </a></p></li><li><p><strong>Research</strong> <a href="http://cba.mit.edu/events/13.03.scifab" target="_blank" rel="noreferrer"> http://cba.mit.edu/events/13.03.scifab </a></p></li><li><p><strong>Hardware</strong> <a href="http://mtm.cba.mit.edu" target="_blank" rel="noreferrer"> http://mtm.cba.mit.edu </a></p></li><li><p><strong>Software</strong> <a href="http://mods.cba.mit.edu" target="_blank" rel="noreferrer"> http://mods.cba.mit.edu </a></p></li><li><p><strong>[Academy Key Personnel(Guru and Instructor)]</strong>(<a href="http://fabacademy.org/2018/docs/FabAcademy-Handbook/academy_roles_and_key_personnel.html" target="_blank" rel="noreferrer">http://fabacademy.org/2018/docs/FabAcademy-Handbook/academy_roles_and_key_personnel.html</a>)</p></li><li><p>Reference fablab</p><ul><li><a href="http://www.ireneposch.net/fablab/" target="_blank" rel="noreferrer">Ars Electronica Center</a></li></ul></li></ul><hr><p>Update time: 2019.12 Update time:2024.2</p>',4)])])}const p=t(i,[["render",l]]);export{m as __pageData,p as default};
